const performance = $('Get Performance Card').first().json;
const summary = $('Get Daily Summary').first().json;
const accuracy = $('Get 30d Accuracy').first().json;
const chartUrl = 'https://griffin-gold-production.up.railway.app/api/charts/weekly-summary.png?size=default';
const accuracyChartUrl = 'https://griffin-gold-production.up.railway.app/api/charts/accuracy.png?days=7&size=default';

const prompt = `Write a 1500-2000 word Medium article analyzing this week's Bitcoin market through the lens of AI predictions. Data:

Performance (7d): ${JSON.stringify(performance, null, 2)}

Daily Summary: ${JSON.stringify(summary, null, 2)}

30-Day Accuracy: ${JSON.stringify(accuracy, null, 2)}

Chart images are available:
- Weekly summary chart: ${chartUrl}
- Accuracy chart: ${accuracyChartUrl}
Embed these chart URLs as images in the article using markdown image syntax.

Structure: compelling title, introduction with hook, methodology section, this week's performance analysis, market insights, what the AI sees ahead, conclusion. Markdown format. Educational and authoritative. Return as JSON: {"title": "...", "content": "..."}.`;

return [{ json: { prompt, chartUrl, accuracyChartUrl } }];

const response = $('Claude Generate').first().json;
const raw = response.content[0].text.trim();

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  const jsonMatch = raw.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) {
    parsed = JSON.parse(jsonMatch[1].trim());
  } else {
    parsed = { title: 'Weekly Bitcoin AI Predictions Analysis', content: raw };
  }
}

return [{ json: { title: parsed.title, content: parsed.content } }];

const title = $('Extract Article').first().json.title;
const content = $('Extract Article').first().json.content;
const now = new Date().toISOString();
console.log(`[${now}] Medium article published: ${title}`);
return [{ json: { status: 'posted', platform: 'medium', timestamp: now, title: title, content_length: content.length } }];
